import pull from "../../../../../../../../../../../subject_repositories/pull-stream/pull.js"

describe("pull", () => {
  it("should handle a pipeline where a through-stream is a function without treating non-object falsy values as objects", () => {
    const collected: number[] = []
    let endCalled = false

    const source = (end: any, cb: Function) => {
      if (end) return cb(end)
      cb(null, 1)
    }

    const sink = (read: Function) => {
      read(null, (end: any, data: any) => {
        if (end) { endCalled = true; return }
        collected.push(data)
      })
    }

    // null as a through-stream: original skips it (s && typeof s === 'object' is false for null)
    // mutated tries null.sink(read) -> throws TypeError
    expect(() => {
      pull(source, null as any, sink)
    }).not.toThrow()
  })
})
```

